messages.content:
h1 {
  color: blue;
  font-size: 24px;
  font-weight: bold;
}

p {
  color: black;
  font-size: 16px;
}

div {
  background-color: #EEE;
  padding: 10px;
}

ul {
  list-style-type: none;
}

li {
  background-color: #DDD;
  padding: 5px;
  margin-bottom: 5px;
}

a {
  text-decoration: none;
  color: red;
}

.button {
  background-color: blue;
  color: white;
  padding: 10px;
  border-radius: 5px;
  text-align: center;
  width: 150px;
  cursor: pointer;
}

.button:hover {
  background-color: darkblue;
}

.button:active {
  background-color: navy;
}

.container {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
}
